// Get the input data from previous node
const items = $input.all();

console.log('=== DEBUG: Input Structure ===');
console.log('Number of input items:', items.length);

if (items.length > 0) {
  const firstItem = items[0];
  console.log('First item keys:', Object.keys(firstItem));
  console.log('First item has json?', 'json' in firstItem);

  if (firstItem.json) {
    console.log('JSON type:', typeof firstItem.json);
    console.log('Is array?', Array.isArray(firstItem.json));
    console.log('JSON value:', JSON.stringify(firstItem.json, null, 2).substring(0, 500) + '...');
  }
}

// Let's try to handle whatever structure we get
let responseData = null;

if (items.length > 0 && items[0].json) {
  const jsonData = items[0].json;

  // Handle different possible structures
  if (Array.isArray(jsonData)) {
    console.log('Response is an array, length:', jsonData.length);
    responseData = jsonData[0]; // First element of array
  } else if (typeof jsonData === 'object') {
    console.log('Response is an object');
    responseData = jsonData; // Direct object
  }
}

if (!responseData) {
  console.error('Could not extract response data');
  // Return empty but don't throw error for debugging
  return { error: 'Could not parse response', rawInput: items };
}

console.log('\n=== Response Data Structure ===');
console.log('Response keys:', Object.keys(responseData));

// Try to extract data with fallbacks
const totalCount = responseData.totalcount || responseData.totalCount || 0;
const dataArray = responseData.data || [];
const dataCount = dataArray.length;
const contentRange = responseData['content-range'] || responseData.contentRange || '';

console.log('\n=== Extracted Values ===');
console.log('Total count:', totalCount);
console.log('Data count:', dataCount);
console.log('Content-Range:', contentRange);

// Parse content-range to get expected count
let expectedCount = 0;
if (contentRange) {
  const match = contentRange.match(/\/(\d+)$/);
  if (match) {
    expectedCount = parseInt(match[1]);
  }
}

console.log('Expected count from range:', expectedCount);

// Check if we have data
if (dataCount === 0) {
  console.warn('⚠️ WARNING: No data in response');
} else {
  console.log('✅ Data received!');

  // Show first item structure
  console.log('\n=== First Item Structure ===');
  const firstItem = dataArray[0];
  console.log('First item keys:', Object.keys(firstItem));
  console.log('First item sample:', JSON.stringify(firstItem, null, 2).substring(0, 300));
}

// Pass through whatever we have
return {
  totalCount,
  dataCount,
  contentRange,
  expectedCount,
  data: dataArray,
  rawResponse: responseData,
  debug: {
    inputItems: items.length,
    firstItemKeys: items.length > 0 ? Object.keys(items[0]) : []
  }
};

// Get data from previous node
const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('No input data');
}

const previousData = items[0].json;

// Extract the data array
const glpiData = previousData.data || [];
const totalCount = glpiData.length;

console.log(`Transforming ${totalCount} GLPI computers...`);

// Transform each computer
const transformedData = glpiData.map((computer, index) => {
  // Extract fields using the numeric keys
  const id = computer['2'] || null;
  const name = computer['1'] || null;
  const serial = computer['5'] || null;
  const otherserial = computer['6'] || null; // Inventory number
  const location = computer['3'] || null;
  const type = computer['4'] || null;
  const processor = computer['17'] || null;
  const date_mod = computer['19'] || null;
  const status = computer['31'] || null;
  const model = computer['40'] || null;

  // For now, we'll set default values for foreign keys
  // These can be updated later with proper lookups
  const entities_id = 0; // Default to Root entity
  const locations_id = 0; // Will need mapping
  const states_id = 0; // Will need mapping
  const computermodels_id = 0; // Will need mapping
  const computertypes_id = 0; // Will need mapping
  const manufacturers_id = 0; // Will need mapping
  const users_id = 0;
  const groups_id = 0;

  // Create database record
  return {
    id: id,
    name: name,
    serial: serial,
    otherserial: otherserial,
    entities_id: entities_id,
    locations_id: locations_id,
    states_id: states_id,
    computermodels_id: computermodels_id,
    computertypes_id: computertypes_id,
    manufacturers_id: manufacturers_id,
    users_id: users_id,
    groups_id: groups_id,
    date_mod: date_mod,
    date_creation: date_mod, // Use same as date_mod for now
    is_deleted: false,
    is_dynamic: false,
    last_sync: new Date().toISOString()
  };
});

// Log sample transformation
console.log('\n=== Sample Transformed Data (First 3 items) ===');
for (let i = 0; i < Math.min(3, transformedData.length); i++) {
  const item = transformedData[i];
  console.log(`Item ${i + 1}:`);
  console.log(`  ID: ${item.id}`);
  console.log(`  Name: ${item.name}`);
  console.log(`  Serial: ${item.serial}`);
  console.log(`  Inventory: ${item.otherserial}`);
  console.log(`  Status from GLPI: ${glpiData[i]['31']}`);
  console.log('---');
}

console.log(`\n✅ Successfully transformed ${transformedData.length} computers`);

// Return transformed data
return transformedData;
